echo "/* Hero Animation */
.hero-animation {
    position: relative;
    display: flex;
    justify-content: center;
    align-items: center;
    height: 5rem; 
    margin-bottom: 1rem;

    .full-text {
        position: absolute;
        display: flex;
        align-items: center;
        white-space: nowrap;
        animation: fadeOutFull 0.5s forwards;
        animation-delay: 2.5s;
        font-size: 3rem;

        .slide-left {
            animation: slideInLeft 1.5s cubic-bezier(0.25, 1, 0.5, 1) forwards;
            margin-right: 0.5rem;
            color: var(--articles-primary);
        }
        .slide-right {
            animation: slideInRight 1.5s cubic-bezier(0.25, 1, 0.5, 1) forwards;
            margin-left: 0.5rem;
        }
    }

    .abbr-text {
        position: absolute;
        display: flex;
        align-items: center;
        opacity: 0;
        animation: fadeInAbbr 0.1s forwards;
        animation-delay: 3s;

        .pop-in {
            display: inline-block;
            animation: popIn 0.8s cubic-bezier(0.34, 1.56, 0.64, 1) forwards;
            animation-delay: 3s;
            font-size: 3rem;
            font-weight: 900;
        }

        .am {
             color: var(--articles-primary);
             margin-right: 1rem;
        }
    }
}

@keyframes slideInLeft {
    from { transform: translateX(-100vw); opacity: 0; }
    to { transform: translateX(0); opacity: 1; }
}

@keyframes slideInRight {
    from { transform: translateX(100vw); opacity: 0; }
    to { transform: translateX(0); opacity: 1; }
}

@keyframes fadeOutFull {
    to { opacity: 0; visibility: hidden; }
}

@keyframes fadeInAbbr {
    to { opacity: 1; }
}

@keyframes popIn {
    0% { transform: scale(0); opacity: 0; }
    60% { transform: scale(1.3); opacity: 1; }
    100% { transform: scale(1); opacity: 1; }
}" >> "f:\My Documents\Sites\project-manager\styles\pages\landing.scss"
